<script setup>
import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import{api}from'../../api'
const username=ref(uni.getStorageSync('rememberMerchant')||''),password=ref(''),remember=ref(Boolean(username.value)),showPwd=ref(false),loading=ref(false)
onShow(()=>{if(uni.getStorageSync('merchantToken'))uni.reLaunch({url:'/pages/merchant/dashboard'})})
async function login(){if(!username.value.trim()||!password.value)return uni.showToast({title:'请输入账号和密码',icon:'none'});loading.value=true;try{const data=await api.merchantLogin({username:username.value.trim(),password:password.value});uni.setStorageSync('merchantToken',data.token);uni.setStorageSync('merchantProfile',data.merchant);if(remember.value)uni.setStorageSync('rememberMerchant',username.value.trim());else uni.removeStorageSync('rememberMerchant');uni.reLaunch({url:'/pages/merchant/dashboard'})}catch(_){password.value=''}finally{loading.value=false}}
</script>
<template><view class="merchant-login"><view class="brand-block"><view class="logo">🍜</view><text class="title">商家管理端</text><text class="muted">登录后可处理订单、管理商品和设置店铺</text></view><view class="form"><view class="field"><text class="field-label">商家账号</text><view class="input-wrap"><text>▦</text><input v-model="username" placeholder="请输入商家账号"/></view></view><view class="field"><text class="field-label">登录密码</text><view class="input-wrap"><text>♢</text><input v-model="password" :password="!showPwd" placeholder="请输入登录密码"/><text @tap="showPwd=!showPwd">{{showPwd?'隐藏':'显示'}}</text></view></view><view class="remember" @tap="remember=!remember"><view :class="{checked:remember}">{{remember?'✓':''}}</view><text>记住账号</text></view><button class="primary-btn" :disabled="loading" @tap="login">{{loading?'登录中…':'登录商家端'}}</button><text class="forgot" @tap="uni.showModal({title:'忘记密码',content:'请联系店铺管理员重置密码',showCancel:false})">忘记密码？</text><view class="demo">💡 本地测试账号：admin_demo · 密码：ShikeTest123</view></view><text class="back" @tap="uni.reLaunch({url:'/pages/login/index'})">返回用户登录</text></view></template>
<style scoped>.merchant-login{min-height:100vh;padding:60rpx 56rpx calc(40rpx + env(safe-area-inset-bottom));display:flex;flex-direction:column;background:#fff}.brand-block{display:flex;flex-direction:column;align-items:center;margin:70rpx 0 60rpx}.logo{width:144rpx;height:144rpx;border-radius:40rpx;background:#fff2e8;text-align:center;line-height:144rpx;font-size:72rpx}.title{margin-top:24rpx;font-size:40rpx;font-weight:800}.brand-block .muted{margin-top:10rpx;font-size:23rpx}.form{flex:1}.input-wrap{height:92rpx;padding:0 22rpx;display:flex;align-items:center;gap:16rpx;border:2rpx solid #eee;border-radius:18rpx}.input-wrap input{flex:1;font-size:27rpx}.input-wrap text:last-child{color:#999;font-size:22rpx}.remember{display:flex;align-items:center;gap:14rpx;margin:12rpx 0 48rpx;color:#666;font-size:24rpx}.remember view{width:32rpx;height:32rpx;border:2rpx solid #ccc;border-radius:50%;text-align:center;line-height:29rpx;color:#fff}.remember .checked{background:#ff8a34;border-color:#ff8a34}.form .primary-btn{width:100%}.forgot{display:block;margin:30rpx;text-align:center;color:#999;text-decoration:underline;font-size:24rpx}.demo{padding:20rpx;border-radius:16rpx;background:#f7f8fa;color:#999;font-size:21rpx}.back{text-align:center;color:#999;font-size:24rpx}</style>
